import Foundation
func valid(_ b: [[Character]], _ r: Int, _ c: Int, _ ch: Character) -> Bool { for i in 0..<9 { if b[r][i] == ch || b[i][c] == ch { return false } }; let br = (r / 3) * 3; let bc = (c / 3) * 3; for i in br..<br+3 { for j in bc..<bc+3 { if b[i][j] == ch { return false } } }; return true }
func solve(_ b: inout [[Character]]) -> Bool { for r in 0..<9 { for c in 0..<9 { if b[r][c] == "." { for ch in Array("123456789") { if valid(b, r, c, ch) { b[r][c] = ch; if solve(&b) { return true }; b[r][c] = "." } }; return false } } }; return true }
let lines = String(data: FileHandle.standardInput.readDataToEndOfFile(), encoding: .utf8)?.split(separator: "\n", omittingEmptySubsequences: false).map { String($0).replacingOccurrences(of: "\r", with: "") } ?? []
if !lines.isEmpty, !lines[0].trimmingCharacters(in: .whitespacesAndNewlines).isEmpty { var idx = 0; let t = Int(lines[idx].trimmingCharacters(in: .whitespacesAndNewlines)) ?? 0; idx += 1; var out: [String] = []; for _ in 0..<t { var b = [[Character]](); for _ in 0..<9 { b.append(Array(idx < lines.count ? lines[idx] : "")); idx += 1 }; _ = solve(&b); out.append(contentsOf: b.map { String($0) }) }; print(out.joined(separator: "\n"), terminator: "") }
